import React from "react";
import { createRoot } from "react-dom/client";
import { AnimatePresence } from "framer-motion";
import "./index.css";  
import App from "./App"; 
import { BrowserRouter } from "react-router-dom"; // ✅ ตรวจสอบว่ามีการ import นี้

const container = document.getElementById("root");
const root = createRoot(container);

root.render(
  <React.StrictMode>
    <BrowserRouter>
      <AnimatePresence>
        <App />
      </AnimatePresence>
    </BrowserRouter>
  </React.StrictMode>
);
